+Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
+  if (auto *II = dyn_cast<IntrinsicInst>(&CI)) {
+    Intrinsic::ID IID = II->getIntrinsicID();
+    switch (IID) {
+    case Intrinsic::fshl: {
+      Value *X = II->getArgOperand(0);
+      Value *Y = II->getArgOperand(1);
+      Value *ShAmt = II->getArgOperand(2);
+
+      if (!match(Y, m_Zero()))
+        break;
+
+      Type *Ty = X->getType();
+      Type *ScalarTy = Ty->getScalarType();
+      auto *ITy = dyn_cast<IntegerType>(ScalarTy);
+      if (!ITy)
+        break;
+
+      unsigned BW = ITy->getBitWidth();
+      ConstantRange CR = computeConstantRange(ShAmt, /*ForSigned=*/false,
+                                              /*UseInstrInfo=*/true, II, &AC,
+                                              &DT);
+      if (!CR.isEmptySet() && CR.getUnsignedMax().ult(BW))
+        return BinaryOperator::CreateShl(X, ShAmt);
+
+      break;
+    }
+    case Intrinsic::vector_reduce_add:
+    case Intrinsic::vector_reduce_and:
+    case Intrinsic::vector_reduce_or: {
+      break;
+    }
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
@@ -3753,6 +3812,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

